      "slug": "modulo-08-rede-entrega-conteudo-03-peering-vpn-direct-connect",
      "title": "VPC Peering, VPN, AWS Direct Connect",
      "module": "modulo-08-rede-entrega-conteudo",
      "moduleLabel": "Rede e CDN",
      "relative": "modulo-08-rede-entrega-conteudo/03-peering-vpn-direct-connect.md",
